var e=JSON.parse(`[{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"여기는……?","JPN":"ここは……？","ENG":"Where am I…?","TWN":"這裡是……？"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"호수는 하나가 되어야만 해……. 하나가 되는 거야…….","JPN":"湖は一つにならないといけない……一つになるのさ……","ENG":"The Lake must be one... Become one...","TWN":"湖水必須合而為一……合而為一……"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"우리와 하나가 되자…… 하나가 되자…….","JPN":"私たちと一つになろう……一つになろう……","ENG":"One with us... One with us...","TWN":"和我們合而為一吧……合而為一……"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"결국…… 실패한 건가?","JPN":"結局……失敗したのか。","ENG":"So... I failed?","TWN":"最終……還是失敗了嗎？"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"약속을 지키는 것도, 누군가를 구하는 것도…….","JPN":"約束を守ることも、誰かを救うことも……","ENG":"To keep a promise, to save someone...","TWN":"無論是信守諾言，還是救人……"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"내 손으로는…… 아무것도 이루지 못한 건가……?","JPN":"俺の手では……何も成し遂げられなかったのか……？","ENG":"I couldn't achieve anything... with my own hands...?","TWN":"難道我什麼都……沒能用我的雙手實現嗎……？"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 나는…….","JPN":"けど俺は……","ENG":"But I...","TWN":"可我……"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"하나가 되자…… 하나가 되자…….","JPN":"一つになろう……一つになろう……","ENG":"Become one... Become one...","TWN":"合而為一吧……合而為一……"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"로이 버넷…… 로이 버넷…….","JPN":"ロイ・バーネット……ロイ・バーネット……","ENG":"Roy Burnett... Roy Burnett...","TWN":"羅伊·伯內特……羅伊·伯內特……"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 나는 살고 싶어! 살고 싶다고!","JPN":"けど、俺は生きたい！　生きたいんだ！","ENG":"But I want to live! I want to live!","TWN":"但是我想活下去！我想活下去！"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"제기랄! 겨우 이런 곳에서 비참하게 죽고 싶지는 않아……!","JPN":"くそ！　こんなところで惨めに死にたくない……！","ENG":"Bollocks! I don't want to die miserably in a place like this...!","TWN":"該死！我不想死在這種地方……！"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"거기 누구 없어요!","JPN":"誰かいませんか！","ENG":"Is anyone there?!","TWN":"有沒有人啊！"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"살려주세요! 살려주세요! 제발……!!","JPN":"助けてください！　助けてください！　頼むから……！！","ENG":"Save me! Save me! Please...!!","TWN":"救命！救命！求求你……！！"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"제기랄……!! 나 좀 여기서 꺼내달라고……!!","JPN":"ちくしょう……！！　ここから出してくれ……！！","ENG":"Dammit...!! Get me out of here...!!","TWN":"該死……！！把我從這裡弄出去啊……！！"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"홍차 폭탄! 집사 할배! 안 들려!? 누구든 좋아! 누구든 좋으니까……!","JPN":"紅茶爆弾！　執事のジジイ！　聞こえてないか！？　誰でもいい、誰でもいいから……！","ENG":"Tea Bomb! Butler! Can anybody hear me?! Anyone will do! Anyone, please...!","TWN":"紅茶炸彈！管家老頭！聽不到嗎？！誰來都行！誰來都行啊……！"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래, 내가 졌어!! 졌다고!!","JPN":"ああ、認める！！　俺の負けだ！！","ENG":"Fine, I lost!! I lost, okay!!","TWN":"好，我輸了！輸了！！"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐든지 하라는 대로 할 테니까, 제발……!!","JPN":"なんでも言う通りにするから、頼むから……！！","ENG":"I'll do whatever you tell me to, so, please...!!","TWN":"我什麼都願意做，求求你……！！"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"하나가 되자, 로이 버넷.","JPN":"一つになろう、ロイ・バーネット。","ENG":"Become one with us, Roy Burnett.","TWN":"合而為一吧，羅伊·伯內特。"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"다들 널 기다리고 있어, 널 탐식하길 기대하고 있어.","JPN":"皆あなたを待っている。あなたを貪食したいと期待している。","ENG":"Everyone's waiting for you. They want to devour you.","TWN":"大家都等著你，等著吃掉你。"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"하나가 되자…… 우리의 숙적.","JPN":"一つになろう……我々の宿敵。","ENG":"Become one with us... our nemesis.","TWN":"合而為一吧……我們的宿敵。"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……하아.","JPN":"……はあ。","ENG":"...*Sigh.*","TWN":"……哈啊。"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"됐어. 이젠 지쳤어. 마음대로 해.","JPN":"もういい、疲れた。勝手にしろ。","ENG":"Whatever. I'm tired now. Do whatever you want.","TWN":"算了，我累了。隨便吧。"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나는 할 만큼 했다고.","JPN":"俺はやれることはやった。","ENG":"I've done enough.","TWN":"我已經盡力了。"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까…….","JPN":"だから……","ENG":"So...","TWN":"所以說……"},"stage":{"bg":"PRYDWEN_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_SHADOW","text":{"KOREA":"기어코 마지막까지 허세를 부리더니.","JPN":"最後まで見栄張っておきながら……","ENG":"You kept bluffing all tough until the end.","TWN":"硬是虛張聲勢到最後。"},"stage":{"bg":"BLACK","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_SHADOW","text":{"KOREA":"결국엔 적에게 목숨을 구걸하는 꼴인가?","JPN":"結局敵に命乞いをするつもりか。","ENG":"And now you're begging for your life.","TWN":"可最終還是沒忍住向敵人求饒了嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_SHADOW","text":{"KOREA":"후후. 저승에 계신 버넷 형님을 만나면, 잔소리를 듣게 생겼구만.","JPN":"ふふ、あの世でバーネットに会ったら、小言を言われる気がするな。","ENG":"Hah hah. I'm going to get scolded when I face your grandfather in the afterlife.","TWN":"呵呵，如果死後見到伯內特大哥，我看又要聽他嘮叨了。"},"stage":{"bg":"BLACK","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_SHADOW","text":{"KOREA":"하지만 자네의 허세는 멋진 정론이었어.","JPN":"だが、君の見栄は立派な正論だった。","ENG":"But your bluffing was solid.","TWN":"但你的虛張聲勢是一種絕妙的哲學。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_SHADOW","text":{"KOREA":"오히려 너무나 올바르기에, 다들 이것저것 핑계를 대가며 외면했을 만큼.","JPN":"正論すぎて、皆あれやこれやと言い訳をして目をそらすほどに。","ENG":"It was so righteous that everyone made excuses to ignore it.","TWN":"反而因為太正確了，所以大家都會找各種藉口視而不見。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그리고 자네는 처음부터 끝까지 그 허세를 지켜내려 했지.","JPN":"そして君は最初から最後まで自分を貫こうとした。","ENG":"And you tried to keep up that bluff from start to finish.","TWN":"而且你自始至終都想守住那個態度。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_SHADOW","text":{"KOREA":"뭐, 내 제자니까 그 정도 근성은 당연하겠지만.","JPN":"俺の弟子だからそれぐらいの根性は当たり前だがな。","ENG":"Well, that willpower is a given for a disciple of mine.","TWN":"當然，既然是我的徒弟，有那點毅力自然是應該的。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"당신은……?","JPN":"あんたは……？","ENG":"You are...?","TWN":"你是……？"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_SHADOW","text":{"KOREA":"하하, 이거 섭섭하구만.","JPN":"はは、これはこれは寂しいな。","ENG":"Hah hah. How upsetting.","TWN":"哈哈，真是令人傷心啊。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_SHADOW","text":{"KOREA":"우리가 알고 지낸 시간이 얼마인데, 그새 날 잊어버렸나?","JPN":"旧知の仲だと思うが、もう俺のことを忘れてしまったのか？","ENG":"We've known each other for so long. Have you forgotten about me already?","TWN":"我們認識了這麼久，這麼快就把我給忘了？"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"모건, 새디어스 모건일세.","JPN":"モーガン……タデウス・モーガンだ。","ENG":"Morgan. Thaddeus Morgan.","TWN":"我叫摩根，薩迪烏斯·摩根。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L11_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자질구레한 일을 처리해 주는 해결사지.","JPN":"色んな仕事を片付ける万事屋みたいなものだ。","ENG":"I'm a problem solver, especially good at picking up the slack.","TWN":"是一個處理各種瑣事的人。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"모건…… 할배……?","JPN":"モーガンの……ジジイ……？","ENG":"Old chap... Morgan...?","TWN":"摩根……老頭……？"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"모건 할배가 왜 여기에……?","JPN":"モーガンのジジイがなぜここに……？","ENG":"Why are you here...?","TWN":"你怎麼會在這裡……？"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"무슨 소리를 하는 거지?","JPN":"何とぼけたことを言っているんだ。","ENG":"What are you talking about?","TWN":"你在說什麼呢？"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"여기서 꺼내 달라고 고래고래 소리치던 사람은 자네 아닌가, 애송이.","JPN":"ここから出してくれと叫んでいたのは君の方じゃないか、小僧。","ENG":"You're the one who was shouting for someone to save you, kid.","TWN":"大吼大叫要人來救你出去的不是你嗎，小鬼。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이거 참, 시끄러워서 잠을 잘 수가 있어야지.","JPN":"ったく、うるさくて聞いていられなかったぞ。","ENG":"I couldn't sleep with all that noise.","TWN":"真是的，吵得我睡不著覺。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"서, 설마……?","JPN":"ま、まさか……","ENG":"W-what...?","TWN":"難，難道……？"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"호오~ 저희의 내면에서 이렇게나 오래 인격을 유지하다니.","JPN":"ほお、我々の内面でこうも長い間人格を保っていられるとは。","ENG":"Ho-oh... I'm surprised you managed to retain your own will for this long within us.","TWN":"喔～竟然能在我們的內心維持這麼長時間的人格。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"굉장한 집념이네요. 새디어스 모건.","JPN":"すごい執念ですね、タデウス・モーガン。","ENG":"What an admirable level of tenacity, Thaddeus Morgan.","TWN":"好厲害執念啊，薩迪烏斯·摩根。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"하지만 이제 그만…… 저희와 하나가 되어주시겠어요?","JPN":"ですがそろそろ……我々と一つになってもらいます。","ENG":"But would you become one with us now?","TWN":"但是到此為止吧……是時候和我們合而為一了！"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"크윽, 이거 성격이 급한 레이디로군.","JPN":"くっ……気の短いレディだな。","ENG":"Kgh, what an impatient little lady.","TWN":"咳，這真是個急性子的女士啊。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"모건 할배……!!","JPN":"モーガンのジジイ……！！","ENG":"Morgan...!!","TWN":"摩根老頭……！！"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 걱정 말게. 소싯적에 넘어왔던 수라장에 비하면 이 정도는 별거 아니야.","JPN":"はは、心配するな。過去に乗り越えてきた修羅場に比べると、どうってこともない。","ENG":"Hah hah, don't worry. This is nothing compared to the mess I've been through in my youth.","TWN":"哈哈，別擔心。與年輕氣盛時亂來的場面相比，這算不上什麼。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"나는 이미 늦었을지 몰라도, 애송이 하나를 빼내는 건 식은 죽 먹기지.","JPN":"俺はもう遅いかもしれないが、小僧一人を外に出すのは造作もない。","ENG":"It might be too late for me, but it's a piece of cake to get one kid out of here.","TWN":"我可能已經沒救了，但把你這個小鬼弄出去還是可以的。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"무슨 짓을 하려는 거야……?","JPN":"何をするつもりだ……？","ENG":"What are you trying to do...?","TWN":"你想幹什麼……？"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그만둬! 할배……!","JPN":"止めろ、ジジイ……！","ENG":"Quit it, Morgan...!","TWN":"住手！老頭……！"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"잘 듣게, 애송이.","JPN":"よく聞け、小僧。","ENG":"Listen, kid.","TWN":"聽好了，小鬼。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"어떤 전설이든, 그 시작은 자네처럼 허세로 시작해.","JPN":"どんな伝説も、最初は君みたいな見栄っ張りから始まる。","ENG":"All legends start with someone's bluff, like you.","TWN":"不管是多偉大的傳說，最開始都是像你一樣的虛張聲勢。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 그 허세를 끝까지 포기하지 않고 결국 진실로 만들어낸다면.","JPN":"だが最後まで諦めずそれを本物にしてみせた時。","ENG":"But if you can keep up with the bluff and ultimately make it a reality,","TWN":"但是，如果你到最後也不放棄那個態度，最終使其成為真實的話。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그제서야 전설은 생명력을 얻고, 사람들의 기억 속에 영원토록 새겨지게 되지.","JPN":"伝説には命が宿り、人々の記憶にも永遠に刻まれるようになる。","ENG":"the legend gains power, and it is forever engraved in the memories of the people.","TWN":"這樣，傳說就會獲得生命力，並永遠銘刻在人們的記憶中。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"할배, 몸이……!!","JPN":"ジジイ、体が……！！","ENG":"Morgan, your body is–!!","TWN":"老頭，你的身體……！！"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까 버넷은 절대 꺾이면 안 돼.","JPN":"だから、バーネットは屈してはならない。","ENG":"So, a Burnett should never break.","TWN":"所以，伯內特，絕對不能屈服啊。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그 전설을 쫓는 이들이 다시금 허세를 부리고, 그 허세가 새로운 전설이 될 때까지 말이야.","JPN":"その伝説を追う者たちがまた見栄を張り、再び新たな伝説が生まれるまでにな。","ENG":"Until the ones who chase after that legend bluff, and the bluff becomes a new legend.","TWN":"直到追逐傳說的人重新虛張聲勢，而那個虛張聲勢又成為新的傳說。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"할배, 제발……!","JPN":"ジジイ、頼むから……！","ENG":"Morgan, no...!","TWN":"老頭，我求求你……！"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"제발 그러지 마……!!","JPN":"やめてくれ……！！","ENG":"Please, don't do this...!!","TWN":"我求你不要這樣……！！"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 이제는…… 자네가 그 전설을 이을 차례야.","JPN":"そして今は……君がその伝説を継ぐ番だ。","ENG":"And now... it's your turn to carry on the legend.","TWN":"現在……該由你去繼承那個傳說了。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"로이 버넷.","JPN":"ロイ・バーネット。","ENG":"Roy Burnett.","TWN":"羅伊·伯內特。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"안 돼! 하지 마! 할배……!","JPN":"駄目だ、やめろジジイ……！","ENG":"No! Don't! Morgan...!","TWN":"不行！不要！老頭……！"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"으아, 으아아아아아아아아아아악……!!","JPN":"うあ、ああああああああああ……！！","ENG":"Aah, AHHHHHHHHHH...!!","TWN":"呃啊，呃啊啊啊啊啊啊啊……！！"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"아무래도 저는 여기까지인 것 같군요. 버넷 형님.","JPN":"どうやら俺はここまでのようです、バーネット。","ENG":"Seems like this is it for me, Sir Burnett.","TWN":"看來我也到此為止了，伯內特大哥。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"그래도 다행이라고 생각합니다.","JPN":"でも、よかったと思いますよ。","ENG":"I think it's a relief, though.","TWN":"但我還是覺得很幸運。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"형님께 물려받은 재주, 하나도 남김없이 녀석에게 전수했으니까요.","JPN":"兄貴から受け継いだ技は残らずやつに教え込みました。","ENG":"I managed to pass on every last skill I learned from you to the kid.","TWN":"從大哥那學來的本事，已經毫無保留地傳給了那個小鬼。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"하하, 오히려 허세는 저보다 한술 더 뜨더군요.","JPN":"はは、見栄っ張りなら俺より一枚上手じゃないかと。","ENG":"Hah hah, his bluffing was even better than mine.","TWN":"哈哈，他的虛張聲勢反而比我更勝一籌。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"그곳에서 보고 계신다면, 앞으로를 기대하셔도 괜찮을 것 같습니다.","JPN":"あそこで見ているなら、今後に期待してもいいですよ。","ENG":"If you're watching, I think you can look forward to his future.","TWN":"如果你在那裡看到了，也可以期待一下他的未來喔。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"저는 마지막까지 형님을 뛰어넘지 못했지만.","JPN":"俺は最後まで兄貴を越えることはできなかったけど。","ENG":"I couldn't surpass you until the end, but.","TWN":"雖然我到最後都沒能超越大哥。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"녀석이라면 분명 형님이 다다른 곳까지.","JPN":"やつならきっと兄貴の辿り着いた境地に……","ENG":"He might be able to reach your level.","TWN":"但如果是那小子，肯定能追上大哥你。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"어쩌면 그 너머까지 갈 수 있을지도 모르겠습니다.","JPN":"もしかするとその向こうまで行けるかもしれません。","ENG":"Or perhaps, even beyond that.","TWN":"甚至，超越你。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아아. 그렇군요.","JPN":"ああ、そういうことか。","ENG":"Ahh, I see.","TWN":"啊，原來如此。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이제야 알겠습니다. 형님.","JPN":"やっとわかりました、兄貴。","ENG":"I understand now.","TWN":"我現在才明白，大哥。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>문턱에 선 사내</color>라는 별명. 전 그닥 마음에 들지 않았습니다만.","JPN":"<color=#ffd34c>扉の前に立つ男</color>というあだ名……俺はあまり気に入ってなかったんですが。","ENG":"I wasn't too fond of the nickname <color=#ffd34c>\\"a man who stood on the verge of greatness\\"</color>.","TWN":"<color=#ffd34c>站在門檻上的男人</color>這個綽號，其實我不太滿意。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"마지막이 되어서야 그 진정한 의미를 알게 되었군요.","JPN":"最後になって、やっとその意味がわかった気がします。","ENG":"But at last, I understand its true meaning.","TWN":"但直到最後我才明白它的真正含義。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"제 역할은 넘지 못할 문턱 앞에 서서.","JPN":"俺の役目は、俺には越えられない扉の前に立って……","ENG":"My role was to stand on the verge of greatness.","TWN":"我的角色便是，站在無法超越的門檻面前。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"다가올 전설을 맞이하며, 그 문을 열어주는 것이었군요.","JPN":"次の伝説を迎え、扉を開けてやるものだったんですね。","ENG":"To greet the upcoming legend and show him the way.","TWN":"迎接即將到來的傳說，為他打開那扇門。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"후후, 그렇게 생각하니 못내 야속한 기분이 드는 건 어쩔 수 없습니다만.","JPN":"ふふ……そう考えると少し苦々しい気持ちになるのは仕方ないですが。","ENG":"Hah hah. It feels a bit harsh, thinking of it like that.","TWN":"呵呵，這麼一想，總覺得你很刻薄呢。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"제가 맡은 역할.","JPN":"俺に任せられた役目。","ENG":"But I've definitely played","TWN":"怎麼樣，我這個角色。"},"stage":{"bg":"BLACK","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"틀림없이 완수하였습니다.","JPN":"きちんと完遂しましたよ。","ENG":"the role I was given.","TWN":"演得還不錯吧？"},"stage":{"bg":"BLACK","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};